import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ShoppingCart, ChevronRight, MessageCircle, ShieldCheck, Truck, Leaf, Star, Award, ChevronLeft, X } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { PRODUCTS, TESTIMONIALS } from '../data/products';

function StarRating({ n = 5 }) {
  return <span style={{ color: '#FFC107', fontSize: 14 }}>{'★'.repeat(n)}{'☆'.repeat(5 - n)}</span>;
}

function ProductCard({ product }) {
  const { addToCart, toggleWishlist, isWishlisted } = useApp();
  const navigate = useNavigate();
  const wishlisted = isWishlisted(product.id);

  return (
    <div className="product-card" onClick={() => navigate(`/products/${product.id}`)}>
      <div className="product-card-img">
        <img src={product.image} alt={product.name} />
        <span className="product-card-badge">{product.category}</span>
        <button className={`product-card-heart${wishlisted ? ' active' : ''}`}
          onClick={e => { e.stopPropagation(); toggleWishlist(product); }}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill={wishlisted ? '#C8102E' : 'none'} stroke={wishlisted ? '#C8102E' : '#999'} strokeWidth="2">
            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
          </svg>
        </button>
      </div>
      <div className="product-card-body">
        <h3>{product.name}</h3>
        <p>{product.description}</p>
        <div className="size-pills">
          {['50g', '100g', '250g', '500g'].map(s => <span className="size-pill" key={s}>{s}</span>)}
        </div>
        <div className="product-card-actions">
          <button className="btn-add-cart" onClick={e => { e.stopPropagation(); addToCart(product); }}>
            <ShoppingCart size={13} /> Add to Cart
          </button>
          <a href="https://wa.me/9779857021032" target="_blank" rel="noreferrer"
            onClick={e => e.stopPropagation()} className="btn-whatsapp-sm">
            <MessageCircle size={16} />
          </a>
        </div>
      </div>
    </div>
  );
}

export default function Home() {
  const navigate = useNavigate();
  const [testiPage, setTestiPage] = useState(0);
  const [heroSlide, setHeroSlide] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState('right');
  const bestsellers = PRODUCTS.slice(0, 8);

  // Hero carousel products - featured items
  const heroProducts = PRODUCTS.slice(0, 6);

  useEffect(() => {
    const timer = setInterval(() => {
      setDirection('right');
      setIsAnimating(true);
      setTimeout(() => {
        setHeroSlide(prev => (prev + 1) % heroProducts.length);
        setIsAnimating(false);
      }, 300);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  const nextSlide = () => {
    setDirection('right');
    setIsAnimating(true);
    setTimeout(() => {
      setHeroSlide(prev => (prev + 1) % heroProducts.length);
      setIsAnimating(false);
    }, 300);
  };

  const prevSlide = () => {
    setDirection('left');
    setIsAnimating(true);
    setTimeout(() => {
      setHeroSlide(prev => (prev - 1 + heroProducts.length) % heroProducts.length);
      setIsAnimating(false);
    }, 300);
  };

  const goToSlide = (index) => {
    if (index === heroSlide) return;
    setDirection(index > heroSlide ? 'right' : 'left');
    setIsAnimating(true);
    setTimeout(() => {
      setHeroSlide(index);
      setIsAnimating(false);
    }, 300);
  };

  const currentProduct = heroProducts[heroSlide];

  return (
    <div>
      {/* HERO SECTION - Interactive Carousel */}
      <section style={hero.section}>
        <div style={hero.content}>
          <div style={hero.badge}>🏔 नेपालका स्वाद</div>
