          <div style={hero.stats}>
            {[['500+', 'Happy Retailers'], ['10+', 'Product Lines'], ['77', 'Districts']].map(([n, l]) => (
              <div key={l} style={hero.stat}>
                <span style={hero.statNum}>{n}</span>
                <span style={hero.statLabel}>{l}</span>
